<?php require_once __DIR__ . '/includes/admin-header.php';
if($_SERVER['REQUEST_METHOD']==='POST'){ validar_csrf(); if(isset($_POST['excluir'])){$pdo->prepare('DELETE FROM notificacoes_clientes WHERE id=?')->execute([$_POST['id']]); registrar_log($pdo,'Notificações','Excluiu notificação ID '.$_POST['id']);}else{$pdo->prepare('INSERT INTO notificacoes_clientes (tipo,canal,assunto,mensagem_padrao,ativo,criado_em) VALUES (?,?,?,?,?,NOW())')->execute([$_POST['tipo'],$_POST['canal'],$_POST['assunto'],$_POST['mensagem_padrao'],isset($_POST['ativo'])?1:0]); registrar_log($pdo,'Notificações','Criou tipo '.$_POST['tipo']);}}
$rows=$pdo->query('SELECT * FROM notificacoes_clientes ORDER BY id DESC')->fetchAll();
?>
<h1>Notificações dos clientes</h1><div class="grid-2"><section class="panel"><h2>Nova mensagem padrão</h2><form method="post" class="form-grid"><input type="hidden" name="csrf_token" value="<?= csrf_token() ?>"><label>Tipo<select name="tipo"><option>pedido_criado</option><option>pedido_pago</option><option>pedido_enviado</option><option>pedido_cancelado</option><option>recuperacao_senha</option></select></label><label>Canal<select name="canal"><option>email</option><option>whatsapp</option><option>sms</option></select></label><label class="wide">Assunto<input name="assunto" required></label><label class="wide">Mensagem padrão<textarea name="mensagem_padrao" required>Olá {{nome}}, seu pedido {{pedido}} foi atualizado.</textarea></label><label class="check"><input type="checkbox" name="ativo" checked> Ativo</label><button class="btn primary">Salvar</button></form></section><section class="panel"><h2>Modelos</h2><div class="table-wrap"><table><thead><tr><th>Tipo</th><th>Canal</th><th>Assunto</th><th></th></tr></thead><tbody><?php foreach($rows as $r): ?><tr><td><?= e($r['tipo']) ?></td><td><?= e($r['canal']) ?></td><td><?= e($r['assunto']) ?></td><td><form method="post"><input type="hidden" name="csrf_token" value="<?= csrf_token() ?>"><input type="hidden" name="id" value="<?= (int)$r['id'] ?>"><button name="excluir">Excluir</button></form></td></tr><?php endforeach; ?></tbody></table></div></section></div><?php require_once __DIR__ . '/includes/admin-footer.php'; ?>
